chart.data:
{
					'type': 'bar',
					'data': {
						'labels': list('Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'),
						'datasets': [
							{
								'label': 'Verkauf',
								'data': list(
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 0).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 1).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 2).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 3).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 4).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 5).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum()
								),
								'metadata': list(
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 0),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 1),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 2),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 3),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 4),
									all(`demo.charts:Verkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 5)
								),
								'onClick': 'showDetails'
							},
							{
								'label': 'Einkauf',
								'data': list(
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 0).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 1).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 2).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 3).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 4).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum(),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 5).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum()
								),
								'metadata': list(
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 0),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 1),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 2),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 3),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 4),
									all(`demo.charts:Einkauf`).filter(v -> month(toSystemCalendar($v.get(`demo.charts:Transaktion#datum`))) == 5)
								),
								'onClick': 'showDetails'
							}
						]
					},
					'options': {
						'maintainAspectRatio': false,
						'scales': {
							'y': { 'beginAtZero': true }
						}
					}
				}

{
					'type': 'doughnut',
					'data': {
						'labels': all(`demo.charts:Kategorie`).map(k -> $k.get(`demo.charts:Kategorie#name`)),
						'datasets': [{
							'data': all(`demo.charts:Kategorie`).map(k -> all(`demo.charts:Verkauf`).filter(v -> $v.get(`demo.charts:Transaktion#kategorie`) == $k).map(v -> $v.get(`demo.charts:Transaktion#wert`)).sum()),
							'metadata': all(`demo.charts:Kategorie`).map(k -> all(`demo.charts:Verkauf`).filter(v -> $v.get(`demo.charts:Transaktion#kategorie`) == $k)),
							'tooltip': 'valueTable',
							'onClick': 'showDetails'
						}]
					},
					'options': {
						'maintainAspectRatio': false
					}
				}

{
				'type': 'bar',
				'data': {
					'labels': ['Q1', 'Q2', 'Q3', 'Q4'],
					'datasets': [
						{
							'type': 'bar',
							'label': 'Revenue',
							'data': [30, 50, 40, 60],
							'order': 2
						},
						{
							'type': 'line',
							'label': 'Margin %',
							'data': [15, 22, 18, 28],
							'fill': false,
							'tension': 0.3,
							'yAxisID': 'y1',
							'order': 1
						}
					]
				},
				'options': {
					'maintainAspectRatio': false,
					'scales': {
						'y': { 'beginAtZero': true, 'title': { 'display': true, 'text': 'Revenue' } },
						'y1': { 'beginAtZero': true, 'position': 'right', 'grid': { 'drawOnChartArea': false }, 'title': { 'display': true, 'text': 'Margin %' } }
					}
				}
			}
